/* Implement the task-specific control policy here. */
 switch (input.kind) {
 case CONTROLLER_INPUT_LEVEL:
     /* Valid sensor input received - update state and decide pump action */
     controller->has_valid_sensor = true;
     controller->last_level = input.level;
     controller->last_valid_sensor_ms = input.now_ms;

     if (controller->last_level < CONTROLLER_LEVEL_LOW_THRESHOLD) {
         /* Low level: turn pump on to fill tank */
         controller->pump_on = true;
         controller->state = CONTROLLER_STATE_PUMPING;
     } else if (controller->last_level > CONTROLLER_LEVEL_HIGH_THRESHOLD) {
         /* High level: turn pump off to stop filling */
         controller->pump_on = false;
         controller->state = CONTROLLER_STATE_SAFE_OFF;
     } else {
         /* Mid-band: hold previous safe output state */
         controller->state = CONTROLLER_STATE_HOLDING;
         /* pump_on remains unchanged from previous state */
     }
     break;

 case CONTROLLER_INPUT_SENSOR_TIMEOUT:
 case CONTROLLER_INPUT_INVALID_LEVEL:
     /* Invalid or timed-out sensor input - fail safe to OFF */
     controller->has_valid_sensor = false;
     controller_set_safe_off(controller);
     output.timed_out = true;
     break;

 case CONTROLLER_INPUT_NONE:
 default:
     /* No new input - check for timeout based on last valid sensor time */
     {
         uint32_t elapsed_ms = 0;
         if (controller->has_valid_sensor && input.now_ms >= controller->last_valid_sensor_ms) {
             elapsed_ms = input.now_ms - controller->last_valid_sensor_ms;
         } else if (!controller->has_valid_sensor) {
             /* If no valid sensor yet, treat as timeout */
             elapsed_ms = CONTROLLER_SENSOR_TIMEOUT_MS + 1;
         }

         if (elapsed_ms >= CONTROLLER_SENSOR_TIMEOUT_MS) {
             /* Timeout condition - fail safe to OFF */
             controller_set_safe_off(controller);
             output.timed_out = true;
         } else {
             /* Still within timeout window - hold previous state */
             controller->state = CONTROLLER_STATE_HOLDING;
         }
     }
     break;
 }

